#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

// Procesator.h
#ifndef PROCESATOR_H
#define PROCESATOR_H

struct Student;

class Procesator {
public:
    virtual void Run(const std::vector<Student>& students) = 0;
    virtual std::string GetName() const = 0;
    virtual ~Procesator() = default;
};

#endif // PROCESATOR_H

// Student.h
#ifndef STUDENT_H
#define STUDENT_H

#include <string>

struct Student {
    std::string name;
    int mate;
    int romana;

    // Deduce constructor from main.cpp: {{"Dan",10,9}}
    Student(const std::string& n, int m, int r) : name(n), mate(m), romana(r) {}
};

#endif // STUDENT_H

// Students.h
#ifndef STUDENTS_H
#define STUDENTS_H

#include <vector>
#include <string>
#include "Student.h"
#include "Procesator.h"

class Students {
private:
    std::vector<Procesator*> processors;
    std::vector<Student> students;

public:
    Students(const std::vector<Student>& initialStudents) : students(initialStudents) {}
    ~Students();

    void print_all() const;
    void analyze(const std::string& processorName);

    Students& operator+=(Procesator* processor);
};

#endif // STUDENTS_H

// AverageMath.h
#ifndef AVERAGEMATH_H
#define AVERAGEMATH_H

#include "Procesator.h"
#include "Student.h"
#include <string>
#include <numeric>
#include <iostream>

class AverageMath : public Procesator {
public:
    void Run(const std::vector<Student>& students) override;
    std::string GetName() const override { return "AverageMath"; }
};

#endif // AVERAGEMATH_H

// BestRomana.h
#ifndef BESTROMANA_H
#define BESTROMANA_H

#include "Procesator.h"
#include "Student.h"
#include <string>
#include <algorithm>
#include <iostream>

class BestRomana : public Procesator {
public:
    void Run(const std::vector<Student>& students) override;
    std::string GetName() const override { return "BestRomana"; }
};

#endif // BESTROMANA_H

// Students.cpp
#include "Students.h"
#include <iostream>

Students::~Students() {
    for (Procesator* p : processors) {
        delete p;
    }
    processors.clear();
}

void Students::print_all() const {
    for (const auto& student : students) {
        std::cout << student.name << " Math: " << student.mate << " Rom: " << student.romana << std::endl;
    }
}

void Students::analyze(const std::string& processorName) {
    for (Procesator* p : processors) {
        if (p->GetName() == processorName) {
            p->Run(students);
            return;
        }
    }
}

Students& Students::operator+=(Procesator* processor) {
    processors.push_back(processor);
    return *this;
}

// AverageMath.cpp
#include "AverageMath.h"

void AverageMath::Run(const std::vector<Student>& students) {
    if (students.empty()) {
        std::cout << GetName() << " = 0" << std::endl;
        return;
    }
    double sum_math = 0;
    for (const auto& student : students) {
        sum_math += student.mate;
    }
    std::cout << GetName() << " = " << static_cast<int>(sum_math / students.size()) << std::endl;
}

// BestRomana.cpp
#include "BestRomana.h"

void BestRomana::Run(const std::vector<Student>& students) {
    if (students.empty()) {
        // Handle case where there are no students
        std::cout << GetName() << " = No students" << std::endl; // Adjust as desired
        return;
    }

    const Student* bestStudent = nullptr;
    for (const auto& student : students) {
        if (bestStudent == nullptr || student.romana > bestStudent->romana) {
            bestStudent = &student;
        }
    }

    if (bestStudent) {
        std::cout << GetName() << " = " << bestStudent->name << " with grade: " << bestStudent->romana << std::endl;
    }
}

// main.cpp - Provided in problem description
#include <iostream>
#include "Students.h"
#include "BestRomana.h"
#include "AverageMath.h"

int main()
{
    Students s({{"Dan",10,9},{"John",9,4},{"Mike", 5,8}});
    (s += new AverageMath())+=new BestRomana();
    s.print_all();
    s.analyze("AverageMath");
    s.analyze("BestRomana");
    return 0;
}
